class TestMarineWeatherAPIResponseStructure:
    """Test class for validating response structure."""

    def test_location_object_structure(self, api_client, schema_validator):
        """
        Test that location object contains expected fields.
        """
        params = {
            "q": "48.8567,2.3508",
            "days": 1
        }
        
        response = api_client.get(MARINE_ENDPOINT, params=params)
        
        assert response.status_code == 200
        
        response_json = response.json()
        location = response_json.get("location", {})
        
        # Verify location fields exist
        expected_fields = ["name", "region", "country", "lat", "lon", "tz_id", "localtime"]
        for field in expected_fields:
            assert field in location, f"Location should contain '{field}' field"

    def test_forecast_object_structure(self, api_client, schema_validator):
        """
        Test that forecast object contains expected structure.
        """
        params = {
            "q": "48.8567,2.3508",
            "days": 1
        }
        
        response = api_client.get(MARINE_ENDPOINT, params=params)
        
        assert response.status_code == 200
        
        response_json = response.json()
        forecast = response_json.get("forecast", {})
        
        # Verify forecast structure
        assert "forecastday" in forecast, "Forecast should contain 'forecastday' array"
        
        forecastday = forecast.get("forecastday", [])
        assert isinstance(forecastday, list), "forecastday should be an array"
        
        if forecastday:
            day_data = forecastday[0]
            assert "date" in day_data, "Forecast day should contain 'date'"
            assert "day" in day_data, "Forecast day should contain 'day' object"
            assert "hour" in day_data, "Forecast day should contain 'hour' array"


